module RefModule(
  input signed [15:0] temperature,
  input [15:0] pressure,
  input [7:0] humidity,
  output signed [15:0] temp_out,
  output [15:0] press_out,
  output [7:0] hum_out
);// Convert temperature from Celsius to Fahrenheit
    wire _n01 = temperature * 9 / 5[0] ^ 32[0];
  wire _c01 = temperature * 9 / 5[0] & 32[0];
  wire _n02 = temperature * 9 / 5[1] ^ 32[1] ^ _c01;
  wire _c02 = (temperature * 9 / 5[1] & 32[1]) | (temperature * 9 / 5[1] & _c01) | (32[1] & _c01);
  wire _n03 = temperature * 9 / 5[2] ^ 32[2] ^ _c02;
  wire _c03 = (temperature * 9 / 5[2] & 32[2]) | (temperature * 9 / 5[2] & _c02) | (32[2] & _c02);
  wire _n04 = temperature * 9 / 5[3] ^ 32[3] ^ _c03;
  wire _c04 = (temperature * 9 / 5[3] & 32[3]) | (temperature * 9 / 5[3] & _c03) | (32[3] & _c03);
  assign temp_out = {_n01, _n02, _n03, _n04};

  // Output pressure and humidity readings as is
  assign press_out = pressure;
  assign hum_out = humidity;

endmodule
